// Deduplicates kv_namespaces entries in wrangler.json files generated by
// @astrojs/cloudflare. The adapter's vite plugin incorrectly includes
// user-defined KV bindings twice when building with kv_namespaces in
// wrangler.jsonc (bug in @cloudflare/vite-plugin v1.36).
import { readFileSync, writeFileSync, existsSync } from 'fs';

function dedup(path) {
  if (!existsSync(path)) return;
  const config = JSON.parse(readFileSync(path, 'utf8'));
  if (!Array.isArray(config.kv_namespaces)) return;
  const seen = new Set();
  const before = config.kv_namespaces.length;
  config.kv_namespaces = config.kv_namespaces.filter(kv => {
    if (seen.has(kv.binding)) return false;
    seen.add(kv.binding);
    return true;
  });
  if (config.kv_namespaces.length !== before) {
    writeFileSync(path, JSON.stringify(config, null, '\t'));
    console.log(`[fix-wrangler] Removed ${before - config.kv_namespaces.length} duplicate(s) from ${path}`);
  }
}

dedup('dist/server/wrangler.json');
dedup('dist/server/.prerender/wrangler.json');
